    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/runtime/schema"
    "k8s.io/client-go/kubernetes"
    "k8s.io/client-go/kubernetes/scheme"
    "k8s.io/client-go/rest"
)

func newClient() (*kubernetes.Clientset, func(), error) {
    server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.Header().Set("Content-Type", "application/json")
        if r.Method == http.MethodPatch && r.URL.Path == "/api/v1/nodes/uppernode" {
            _ = json.NewEncoder(w).Encode(&corev1.Node{ObjectMeta: metav1.ObjectMeta{Name: "uppernode", Labels: map[string]string{}}})
            return
        }

        w.WriteHeader(http.StatusNotFound)
        _ = json.NewEncoder(w).Encode(&metav1.Status{
            Status:  metav1.StatusFailure,
            Reason:  metav1.StatusReasonNotFound,
            Message: "nodes not found",
            Code:    http.StatusNotFound,
        })
    }))

    client, err := kubernetes.NewForConfig(&rest.Config{
        Host: server.URL,
        ContentConfig: rest.ContentConfig{
            GroupVersion:         &schema.GroupVersion{Version: "v1"},
            NegotiatedSerializer: scheme.Codecs.WithoutConversion(),
        },
    })
    if err != nil {
        server.Close()
        return nil, nil, err
    }
    return client, server.Close, nil
}

func tryLabel(nodeName string) error {
    client, closeServer, err := newClient()
    if err != nil {
        return err
    }
    defer closeServer()

    svc := &corev1.Service{
        ObjectMeta: metav1.ObjectMeta{Name: "web", Namespace: "default"},
        Spec:       corev1.ServiceSpec{LoadBalancerIP: "192.0.2.10"},
    }
    return labeler.NewManager(nodeName, client).AddLabel(context.Background(), svc)
}

func main() {
    uppercase := "UpperNode"
    err := tryLabel(uppercase)
    fmt.Printf("uppercase lookup %q: %v\n", uppercase, err)
    if err == nil || !apierrors.IsNotFound(err) {
        fmt.Println("FAIL: expected uppercase node lookup to fail with NotFound")
        return
    }

    normalized := strings.ToLower(uppercase)
    err = tryLabel(normalized)
    fmt.Printf("normalized lookup %q: %v\n", normalized, err)
    if err != nil {
        fmt.Println("FAIL: expected normalized node lookup to succeed")
        return
    }

    fmt.Println("PASS: node labeling requires lowercased RFC1123 node names")
}
EOF
